import{c as t,Q as a,j as n,m as r}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"Plans","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/finance/plans.md","filePath":"guide/admin/finance/plans.md","lastUpdated":1778862269000}'),i={name:"guide/admin/finance/plans.md"};function o(s,e,l,d,c,u){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="plans" tabindex="-1">Plans <a class="header-anchor" href="#plans" aria-label="Permalink to &quot;Plans&quot;">​</a></h1><p>The <strong>Finance → Plans</strong> page is where you define billing plans, version them, and bind meters to their limits and prices. See <a href="./../../concepts/plans-and-meters">Plans &amp; Meters</a> for the conceptual model.</p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p>The page is card-based, one card per plan. Header has a <strong>Create Custom Plan</strong> button (top right).</p><h2 id="plan-card" tabindex="-1">Plan card <a class="header-anchor" href="#plan-card" aria-label="Permalink to &quot;Plan card&quot;">​</a></h2><p>Each card shows:</p><ul><li>Plan <strong>name</strong>.</li><li>Status badges: <ul><li><strong>Built-in</strong> / <strong>Custom</strong>.</li><li><strong>Billing interval</strong> — Monthly / Quarterly / Annual / Perpetual.</li></ul></li><li><strong>Version selector</strong> — if the plan has multiple versions, a dropdown lets you switch which version the table displays. Useful for reviewing retired versions.</li><li>Effective date range.</li><li>Meter count.</li><li><strong>Add Version</strong> button.</li><li>Meter limits table.</li></ul><h3 id="meter-limits-table" tabindex="-1">Meter limits table <a class="header-anchor" href="#meter-limits-table" aria-label="Permalink to &quot;Meter limits table&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Meter</strong></td><td>Display name and key.</td></tr><tr><td><strong>Included Qty</strong></td><td>Units included before overage. &quot;Unlimited&quot; means no cap. <code>0</code> with a non-zero overage price means &quot;pay per unit from zero&quot;.</td></tr><tr><td><strong>Overage Unit Price / Interval</strong></td><td>Cost per unit above the included quantity. <strong>$0 means hard limit</strong> — usage above the cap is blocked, not charged.</td></tr><tr><td><strong>Currency</strong></td><td>USD.</td></tr></tbody></table><h2 id="creating-a-custom-plan" tabindex="-1">Creating a custom plan <a class="header-anchor" href="#creating-a-custom-plan" aria-label="Permalink to &quot;Creating a custom plan&quot;">​</a></h2><p>Click <strong>Create Custom Plan</strong>. The modal asks for:</p><ul><li><strong>Display name</strong> — auto-generates an internal plan key.</li><li><strong>Billing Interval</strong> — Monthly / Quarterly / Annual / Perpetual.</li><li><strong>Meter limits</strong> — one row per meter. For each meter, select it, enter its included quantity, and its overage unit price.</li></ul><p>Click <strong>Create Plan</strong>. The plan appears as a new card.</p><h2 id="creating-a-new-plan-version" tabindex="-1">Creating a new plan version <a class="header-anchor" href="#creating-a-new-plan-version" aria-label="Permalink to &quot;Creating a new plan version&quot;">​</a></h2><p>Click <strong>Add Version</strong> on a plan card.</p><ul><li>The modal pre-fills with the current version&#39;s meter limits.</li><li>Edit any limits you want to change.</li><li>Click <strong>Create v[N]</strong>.</li></ul><p>The previous version is automatically retired (its retirement date is set), and the new version becomes current. Existing customers stay pinned to whatever version they had — they must be <strong>upgraded</strong> to the new version explicitly. The Console flags out-of-date customers in <a href="./customers">Finance Customers</a> with a warning icon and offers an upgrade banner on their billing page.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Plans have no inline &quot;edit current version&quot; affordance. To change something, create a new version. This preserves history and prevents accidentally rewriting active invoices&#39; source-of-truth.</li><li>Built-in plans are read-only. Use them as templates if you need a similar custom plan.</li><li>Hard limits (<code>$0</code> overage) prevent overage charges by blocking usage above the cap. Customers see this as a quota enforcement in their portal.</li><li>The page does not paginate. If the plan list grows long, use the version selector inside each plan card to focus on what you need.</li></ul>',19)])])}const g=t(i,[["render",o]]);export{p as __pageData,g as default};
